CREATE   PROC [dbo].[StockBalances_GoodsReceipt]
(
	@SourceType NVARCHAR(50),
	@makho nvarchar(50),
	@mancc nvarchar(50),
	@id_dathang NVARCHAR(50),
	@sopn NVARCHAR(50),
	@mavt NVARCHAR(200),
	@slnhap DECIMAL(18, 3),
	@soluong_du DECIMAL(18, 3),
	@ghichu NVARCHAR(MAX),
	@nguoinhap NVARCHAR(50),
	@idchitiet NVARCHAR(50),
	@gianhap DECIMAL(18, 3),
	@BatchNo NVARCHAR(50),
	@FscId int = NULL,
	@NhomNguyenLieu int = NULL,
	@MaLoNguyenLieu2 nvarchar(50) = NULL,
	@loaitien nvarchar(50) = NULL,
	@hansudung date = NULL
)
AS
BEGIN
	DECLARE @ngaynhap DATETIME = GETDATE();
	DECLARE @SourceId INT;

	-- GHI CHI TIẾT PHIẾU NHẬP
	INSERT INTO tr_ctphieunhap (
		id_dathang, sopn, mavt, slnhap, soluong_du, 
		ghichu, ngaynhap, nguoinhap, idchitiet, gianhap, BatchNo, 
		FscId, NhomNguyenLieu, MaLoNguyenLieu2, loaitien, hansudung
	) VALUES (
		@id_dathang, @sopn, @mavt, @slnhap, @soluong_du, 
		@ghichu, @ngaynhap, @nguoinhap, @idchitiet, @gianhap, @BatchNo,
		@FscId, @NhomNguyenLieu, @MaLoNguyenLieu2, @loaitien, @hansudung
	)

	SET @SourceId = SCOPE_IDENTITY();

	-- ĐIỀU CHỈNH LẠI MÃ KHO THEO MÃ CHI TIẾT (1 MÃ CHỈ NẰM Ở 1 KHO)
	SET @makho = dbo.ufn_GetWHSMaterial(@mavt);

	-- GHI LỊCH SỬ GIAO DỊCH NHẬP KHO
	INSERT INTO StockTransaction
	(
		TransactionDate, SourceType, SourceId, WarehouseCode, MaterialCode,
		BatchNo, Quantity, UnitPrice, SupplierCode, CreatedBy, Note,
		FscId, NhomNguyenLieu, MaLoNguyenLieu2, Currency, ExpDate
	)
	VALUES (
		@ngaynhap, @SourceType, @SourceId, @makho, @mavt,
		@BatchNo, (@slnhap + @soluong_du), @gianhap, @mancc, @nguoinhap, @ghichu,
		@FscId, @NhomNguyenLieu, @MaLoNguyenLieu2, @loaitien, @hansudung
	)

	-- CẬP NHẬT TỒN KHO
	IF EXISTS (SELECT 1 FROM StockBalances WHERE WarehouseCode = @makho AND MaterialCode = @mavt AND BatchNo = @BatchNo)
	BEGIN
		UPDATE StockBalances
		SET Quantity = Quantity + (@slnhap + @soluong_du)
		WHERE WarehouseCode = @makho AND MaterialCode = @mavt AND BatchNo = @BatchNo
	END
	ELSE
	BEGIN
		INSERT INTO StockBalances (WarehouseCode, MaterialCode, BatchNo, Quantity, FscId, NhomNguyenLieu, MaLoNguyenLieu2, ExpDate)
		VALUES (@makho, @mavt, @BatchNo, (@slnhap + @soluong_du), @FscId, @NhomNguyenLieu, @MaLoNguyenLieu2, @hansudung)
	END

	IF @idchitiet IS NOT NULL AND ISNUMERIC(@idchitiet) = 1
	BEGIN
		UPDATE tr_dondathang_chitiet
		SET sl_danhan = COALESCE(sl_danhan, 0) + @slnhap,
			sl_conlai = COALESCE(sl_conlai, soluong) - @slnhap
		WHERE id = @idchitiet
	END
END
